def verify(answer):
    from math import gcd
    from functools import reduce
    from itertools import combinations

    # Factorize 2025
    n = 2025
    # 2025 = 3^4 * 5^2
    # So divisors are of the form 3^a * 5^b where 0<=a<=4, 0<=b<=2
    divisors = []
    for a in range(5):
        for b in range(3):
            divisors.append(3**a * 5**b)

    # Total number of nonempty subsets of divisors
    total_nonempty = 2**len(divisors) - 1

    # Count subsets where LCM is exactly 2025
    count_good = 0

    # Helper function to compute LCM
    def lcm(a, b):
        return abs(a * b) // gcd(a, b)

    def lcm_of_list(lst):
        if not lst:
            return 1
        return reduce(lcm, lst)

    # We cannot iterate over all subsets if too large, but len(divisors) = 15 -> 2^15 = 32768, manageable
    from itertools import chain, combinations
    def all_subsets(s):
        return chain(*map(lambda x: combinations(s, x), range(1, len(s)+1)))  # nonempty

    for subset in all_subsets(divisors):
        if lcm_of_list(subset) == 2025:
            count_good += 1

    # The probability is count_good / total_nonempty, reduce fraction
    g = gcd(count_good, total_nonempty)
    m = count_good // g
    n = total_nonempty // g
    result = m + n

    try:
        return int(str(answer).strip()) == result
    except Exception:
        return False

