    def greedy_coins(n):
        count = 0
        for coin in [25, 10, 1]:
            num = n // coin
            count += num
            n -= num * coin
        return count

    def min_coins(n):
        # Since coins are 1, 10, 25, we can use dynamic programming for small n
        dp = [float('inf')] * (n + 1)
        dp[0] = 0
        for i in range(1, n + 1):
            for coin in [1, 10, 25]:
                if coin <= i:
                    dp[i] = min(dp[i], dp[i - coin] + 1)
        return dp[n]

    success_count = 0
    for N in range(1, 1001):
        if greedy_coins(N) == min_coins(N):
            success_count += 1

